/* FPS Counter */
#fps-counter {
  position: absolute;
  top: 10px;
  right: 10px;
  color: white;
  font-family: monospace;
  font-size: 16px;
  text-shadow: 1px 1px 1px black;
  z-index: 1001;
}

Edits.Anchor:
#hud {
--scale: 3;
position: fixed;
inset: 0;
z-index: 1000;
pointer-events: none;
}

Edits.Content:
// FPS counter update
const now = performance.now();
if (!window._fpsLastTime) window._fpsLastTime = now;
const fps = Math.round(1000 / (now - window._fpsLastTime));
window._fpsLastTime = now;

const fpsElement = document.getElementById('fps-counter') || (() => {
  const el = document.createElement('div');
  el.id = 'fps-counter';
  document.getElementById('hud').appendChild(el);
  return el;
})();
fpsElement.textContent = `${fps} FPS`;
